const root = $json;
const src =
  root.body && typeof root.body === 'object' && !Array.isArray(root.body)
    ? { ...root, ...root.body }
    : root;

function toText(v) {
  if (v == null) return '';
  if (typeof v === 'string') return v;
  if (typeof v === 'number' || typeof v === 'boolean') return String(v);
  if (Array.isArray(v)) return v.map(toText).join('\n');
  if (typeof v === 'object') {
    if (v.text != null) return toText(v.text);
    if (v.mensagem != null) return toText(v.mensagem);
    if (v.content != null) return toText(v.content);
    if (v.body != null) return toText(v.body);
    return '';
  }
  return String(v);
}

function toCliente(v) {
  if (!v) return 'Cliente';
  if (typeof v === 'string') return v.trim() || 'Cliente';
  if (typeof v === 'object') {
    const n = v.name || v.nome || v.pushName || '';
    return String(n).trim() || 'Cliente';
  }
  return 'Cliente';
}

const mensagem = toText(
  src.mensagem ?? src.message ?? src.mensagens ?? src.messages ?? (typeof src.body === 'string' ? src.body : '') ?? ''
).replace(/\s+/g, ' ').trim();

if (!mensagem || mensagem.length < 1) {
  throw new Error('Payload sem mensagem valida');
}

const ticketRaw = src.ticket_id ?? src.ticket?.id ?? src.conversation_id ?? src.conversationId ?? '';
const ticket_id = String(ticketRaw).trim();

const cliente_nome = toCliente(
  typeof src.cliente === 'object' && src.cliente !== null
    ? src.cliente
    : src.contact || src.customer || (typeof src.cliente === 'string' ? src.cliente : null),
);

let cliente_telefone = String(
  src.cliente_telefone ??
    src.telefone ??
    src.phone ??
    src.phoneNumber ??
    (typeof src.cliente === 'object' && src.cliente !== null
      ? (src.cliente.telefone || src.cliente.phone || '')
      : '') ??
    src.contact?.phoneNumber ??
    src.from ??
    ''
).replace(/\D/g, '');

if ((!cliente_telefone || cliente_telefone.length < 8) && typeof src.cliente === 'string') {
  const d = src.cliente.replace(/\D/g, '');
  if (d.length >= 8) cliente_telefone = d;
}

if (!cliente_telefone || cliente_telefone.length < 8) {
  throw new Error(
    'Telefone ausente. WillTalk 2025+ envia cliente_telefone no JSON do webhook; reinicie o servidor WillTalk apos atualizar.',
  );
}

const canal = 'whatsapp';
const event_id = src.event_id ?? src.externalId ?? 'evt-' + Date.now() + '-' + Math.random().toString(36).slice(2, 8);
const organization_id = src.organization_id ?? src.organizationId ?? '';
const data_evento = src.data_evento ?? src.dataEvento ?? src.timestamp ?? new Date().toISOString();

return [{
  json: {
    ticket_id,
    event_id,
    organization_id,
    canal,
    cliente_nome,
    cliente_telefone,
    mensagem,
    data_evento,
    texto: mensagem
  }
}];

const triageData = $('3. Upsert + Triagem WillTalk').item.json;
const normalizado = $('2. Normalizar Payload').item.json;

return [{
  json: {
    status: 'triagem_pendente',
    action: triageData.action,
    menuAttempts: triageData.menuAttempts,
    shouldReply: triageData.shouldReply,
    replyText: triageData.replyText,
    reason: 'Triagem nao completa — resposta de menu enviada pelo WillTalk diretamente via WhatsApp. Cerebro nao gera resposta AI ate a triagem finalizar.',
    ticket_id: normalizado.ticket_id || triageData.conversationId
  }
}];
